void createAndCopyBook() {
    Book book1("The Great Gatsby", 1);
    Book book2 = book1;
    std::cout << "Created book1 (ID: " << book1.getTitle() << ") and book2 (ID: " << book2.getTitle() << ") via shallow copy." << std::endl;
}
